from collections import deque
from typing import List
import sys
sys.setrecursionlimit(1 << 25)

def solve(nums: List[int]) -> int:
    n = len(nums)
    if n == 0:
        return 0
    max_num = 10**6
    spf = list(range(max_num + 1))
    for i in range(2, int(max_num**0.5) + 1):
        if spf[i] == i:
            for j in range(i*i, max_num+1, i):
                if spf[j] == j:
                    spf[j] = i

    from collections import defaultdict
    prime_to_indices = defaultdict(list)
    for idx, num in enumerate(nums):
        if num == 1:
            continue
        x = num
        primes = set()
        while x != 1:
            p = spf[x]
            primes.add(p)
            while x % p == 0:
                x //= p
        for p in primes:
            prime_to_indices[p].append(idx)

    visited = [False] * n
    q = deque()
    q.append((0, 0))
    visited[0] = True
    while q:
        pos, steps = q.popleft()
        if pos == n - 1:
            return steps
        for next_pos in [pos - 1, pos + 1]:
            if 0 <= next_pos < n and not visited[next_pos]:
                visited[next_pos] = True
                q.append((next_pos, steps + 1))
        num = nums[pos]
        if num == 1:
            continue
        if spf[num] == num:
            p = num
            for j in prime_to_indices[p]:
                if j != pos and not visited[j]:
                    visited[j] = True
                    q.append((j, steps + 1))
    return -1
