import math
from collections import deque, defaultdict

def solve(nums: list[int]) -> int:
    n = len(nums)
    if n == 0:
        return 0

    max_val = 10**6
    is_prime = [True] * (max_val + 1)
    is_prime[0] = is_prime[1] = False
    for i in range(2, int(math.sqrt(max_val)) + 1):
        if is_prime[i]:
            for j in range(i * i, max_val + 1, i):
                is_prime[j] = False

    prime_to_indices = defaultdict(list)
    for idx, num in enumerate(nums):
        if num == 1:
            continue
        factors = set()
        x = num
        if x % 2 == 0:
            factors.add(2)
            while x % 2 == 0:
                x //= 2
        i = 3
        while i * i <= x:
            if x % i == 0:
                if is_prime[i]:
                    factors.add(i)
                while x % i == 0:
                    x //= i
            i += 2
        if x > 1:
            if is_prime[x]:
                factors.add(x)
        for p in factors:
            prime_to_indices[p].append(idx)

    visited = [False] * n
    queue = deque()
    queue.append((0, 0))
    visited[0] = True

    while queue:
        i, steps = queue.popleft()
        if i == n - 1:
            return steps
        for di in (-1, 1):
            ni = i + di
            if 0 <= ni < n and not visited[ni]:
                visited[ni] = True
                queue.append((ni, steps + 1))
        if is_prime[nums[i]]:
            for j in prime_to_indices.get(nums[i], []):
                if j != i and not visited[j]:
                    visited[j] = True
                    queue.append((j, steps + 1))

    return -1
